import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import javax.sql.DataSource;

public class BankingTransactionProcessor {

    private final DataSource dataSource;

    public BankingTransactionProcessor(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    /**
     * Processes a financial transaction (withdrawal or deposit) in a concurrency-safe manner.
     *
     * Uses SELECT ... FOR UPDATE to acquire a row-level lock within a serializable transaction,
     * ensuring no race condition between checking the balance and updating it.
     *
     * @param accountId         the account to operate on
     * @param transactionAmount positive for deposit, negative for withdrawal
     * @param transactionId     a unique idempotency key for this transaction
     * @throws InsufficientFundsException if a withdrawal would overdraw the account
     * @throws InvalidTransactionException if the transaction amount is zero or the account doesn't exist
     * @throws DuplicateTransactionException if this transactionId has already been processed
     * @throws SQLException for any database-level error
     */
    public void processTransaction(long accountId, double transactionAmount, String transactionId)
            throws SQLException, InsufficientFundsException, InvalidTransactionException, DuplicateTransactionException {

        if (transactionAmount == 0) {
            throw new InvalidTransactionException("Transaction amount must not be zero.");
        }
        if (transactionId == null || transactionId.isBlank()) {
            throw new InvalidTransactionException("Transaction ID must not be null or blank.");
        }

        Connection conn = null;
        try {
            conn = dataSource.getConnection();
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            // Step 1: Idempotency check — prevent duplicate processing of the same transaction.
            // Uses SELECT ... FOR UPDATE on the transaction log (or an INSERT with unique constraint).
            if (isTransactionAlreadyProcessed(conn, transactionId)) {
                conn.rollback();
                throw new DuplicateTransactionException(
                        "Transaction " + transactionId + " has already been processed.");
            }

            // Step 2: Acquire an exclusive row-level lock on the account row and read the balance.
            // This prevents any other concurrent transaction from reading or modifying this row
            // until we commit or rollback, eliminating the TOCTOU race condition.
            double currentBalance;
            String selectForUpdate = "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE";
            try (PreparedStatement ps = conn.prepareStatement(selectForUpdate)) {
                ps.setLong(1, accountId);
                try (ResultSet rs = ps.executeQuery()) {
                    if (!rs.next()) {
                        conn.rollback();
                        throw new InvalidTransactionException(
                                "Account " + accountId + " does not exist.");
                    }
                    currentBalance = rs.getDouble("balance");
                }
            }

            // Step 3: Validate — for withdrawals, ensure sufficient funds.
            double newBalance = currentBalance + transactionAmount;
            if (newBalance < 0) {
                conn.rollback();
                throw new InsufficientFundsException(
                        "Insufficient funds in account " + accountId +
                        ". Current balance: " + currentBalance +
                        ", attempted withdrawal: " + Math.abs(transactionAmount));
            }

            // Step 4: Atomically update the balance.
            // As an additional safety net, the WHERE clause re-checks the balance hasn't drifted
            // (belt-and-suspenders alongside the FOR UPDATE lock).
            String updateBalance =
                    "UPDATE accounts SET balance = ?, last_updated = CURRENT_TIMESTAMP " +
                    "WHERE account_id = ? AND balance = ?";
            try (PreparedStatement ps = conn.prepareStatement(updateBalance)) {
                ps.setDouble(1, newBalance);
                ps.setLong(2, accountId);
                ps.setDouble(3, currentBalance);
                int rowsUpdated = ps.executeUpdate();
                if (rowsUpdated != 1) {
                    conn.rollback();
                    throw new SQLException(
                            "Balance update failed unexpectedly for account " + accountId +
                            ". Possible concurrent modification despite row lock.");
                }
            }

            // Step 5: Record the transaction for idempotency and audit.
            String insertTransaction =
                    "INSERT INTO transaction_log (transaction_id, account_id, amount, new_balance, created_at) " +
                    "VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP)";
            try (PreparedStatement ps = conn.prepareStatement(insertTransaction)) {
                ps.setString(1, transactionId);
                ps.setLong(2, accountId);
                ps.setDouble(3, transactionAmount);
                ps.setDouble(4, newBalance);
                ps.executeUpdate();
            }

            conn.commit();

        } catch (SQLException | InsufficientFundsException | InvalidTransactionException |
                 DuplicateTransactionException e) {
            if (conn != null) {
                try {
                    conn.rollback();
                } catch (SQLException rollbackEx) {
                    e.addSuppressed(rollbackEx);
                }
            }
            throw e;
        } finally {
            if (conn != null) {
                try {
                    conn.setAutoCommit(true);
                } catch (SQLException ignored) {
                    // best effort
                }
                try {
                    conn.close();
                } catch (SQLException ignored) {
                    // best effort
                }
            }
        }
    }

    /**
     * Checks whether a transaction with the given ID has already been recorded.
     * Must be called within an active transaction that holds appropriate locks.
     */
    private boolean isTransactionAlreadyProcessed(Connection conn, String transactionId)
            throws SQLException {
        String query = "SELECT 1 FROM transaction_log WHERE transaction_id = ? FOR UPDATE";
        try (PreparedStatement ps = conn.prepareStatement(query)) {
            ps.setString(1, transactionId);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next();
            }
        }
    }

    // --- Custom exception classes ---

    public static class InsufficientFundsException extends Exception {
        public InsufficientFundsException(String message) {
            super(message);
        }
    }

    public static class InvalidTransactionException extends Exception {
        public InvalidTransactionException(String message) {
            super(message);
        }
    }

    public static class DuplicateTransactionException extends Exception {
        public DuplicateTransactionException(String message) {
            super(message);
        }
    }
}